// src/commands/deploy.ts
import { existsSync as existsSync5, readFileSync as readFileSync3 } from "fs";
import { join as join5 } from "path";
function deployCommand(program) {
  program.command("deploy [project]").description("Deploy project via Dokploy").option("--domain <domain>", "Custom domain for deployment").option("--env <vars...>", "Environment variables (KEY=value)").action(async (projectName, options) => {
    console.log("\u{1F680} Deploying with Dokploy");
    console.log("");
    const dokploy = new DokployService();
    try {
      await dokploy.install();
      const statePath = join5(process.cwd(), ".hestia", "builder-state.json");
      let projectId = null;
      if (existsSync5(statePath)) {
        const state = JSON.parse(readFileSync3(statePath, "utf-8"));
        if (projectName) {
          const status2 = await dokploy.getStatus();
          const found = status2.projects.find((p) => p.name === projectName);
          if (found) {
            projectId = found.id;
          }
        } else if (state.components?.dokploy?.projectName) {
          const status2 = await dokploy.getStatus();
          const found = status2.projects.find(
            (p) => p.name === state.components.dokploy.projectName
          );
          if (found) {
            projectId = found.id;
          }
        }
      }
      if (!projectId) {
        if (projectName) {
          console.log(`Creating new Dokploy project: ${projectName}`);
          await dokploy.createProject(projectName);
          const status2 = await dokploy.getStatus();
          const newProject = status2.projects.find((p) => p.name === projectName);
          if (newProject) {
            projectId = newProject.id;
          }
        } else {
          throw new Error(
            'No project specified. Run "eve builder init <name>" first or provide a project name.'
          );
        }
      }
      if (!projectId) {
        throw new Error("Could not determine project to deploy");
      }
      if (options.domain) {
        console.log(`Configuring custom domain: ${options.domain}`);
        await dokploy.configureDomain(options.domain);
      }
      if (options.env && options.env.length > 0) {
        console.log("Setting environment variables:");
        for (const envVar of options.env) {
          const [key, value] = envVar.split("=");
          if (key && value) {
            console.log(`  ${key}=${"*".repeat(value.length)}`);
          }
        }
      }
      console.log("");
      console.log("Starting deployment...");
      console.log("-------------------------------------------");
      await dokploy.deploy(projectId);
      const status = await dokploy.getStatus();
      const project = status.projects.find((p) => p.id === projectId);
      console.log("-------------------------------------------");
      console.log("\u2705 Deployment successful!");
      console.log("");
      if (project?.url) {
        console.log(`\u{1F310} Project URL: ${project.url}`);
      }
      if (options.domain) {
        console.log(`\u{1F517} Custom Domain: https://${options.domain}`);
      }
      console.log("");
      console.log("Deployment status:", project?.status);
    } catch (error) {
      console.error("\u274C Deployment failed:", error);
      process.exit(1);
    }
  });
}

// src/commands/stack.ts
import { existsSync as existsSync6, mkdirSync as mkdirSync5, writeFileSync as writeFileSync5 } from "fs";
import { join as join6 } from "path";
import { execSync as execSync4 } from "child_process";
var COMPOSE = `services:
  eve-builder-site:
    image: nginx:alpine
    container_name: eve-builder-site
    restart: unless-stopped
    ports:
      - "127.0.0.1:9080:80"
    volumes:
      - \${EVE_BUILDER_SITE_DIR}:/usr/share/nginx/html:ro
    networks:
      - eve-network

networks:
  eve-network:
    external: true
`.trim();
function composePath(cwd) {
  return join6(cwd, ".eve", "builder-docker-compose.yml");
}
function defaultSiteDir(cwd) {
  return join6(cwd, ".eve", "builder-site", "public");
}
function ensureSiteContent(siteDir) {
  mkdirSync5(siteDir, { recursive: true });
  const index = join6(siteDir, "index.html");
  if (!existsSync6(index)) {
    writeFileSync5(
      index,
      `<!DOCTYPE html><html lang="en"><head><meta charset="utf-8"/><title>Eve Builder</title></head><body><h1>Builder base site</h1><p>Static root for OpenCode output. Served at http://127.0.0.1:9080</p></body></html>
`
    );
  }
}
function stackCommand(program) {
  const stack = program.command("stack").description("Nginx base site stack (Docker, eve-network, :9080)");
  stack.command("up").description("Start nginx static site container").action(() => {
    const cwd = process.cwd();
    const siteDir = defaultSiteDir(cwd);
    ensureSiteContent(siteDir);
    mkdirSync5(join6(cwd, ".eve"), { recursive: true });
    writeFileSync5(composePath(cwd), COMPOSE, "utf-8");
    try {
      execSync4("docker network create eve-network", { stdio: "ignore" });
    } catch {
    }
    const env = { ...process.env, EVE_BUILDER_SITE_DIR: siteDir };
    execSync4(`docker compose -f "${composePath(cwd)}" up -d`, {
      stdio: "inherit",
      cwd,
      env
    });
    console.log(`
Builder site: http://127.0.0.1:9080  (files under ${siteDir})`);
  });
  stack.command("down").description("Stop nginx static site container").action(() => {
    const cwd = process.cwd();
    const siteDir = defaultSiteDir(cwd);
    const env = { ...process.env, EVE_BUILDER_SITE_DIR: siteDir };
    if (!existsSync6(composePath(cwd))) {
      console.log("No generated compose file. Run: eve builder stack up");
      return;
    }
    execSync4(`docker compose -f "${composePath(cwd)}" down`, {
      stdio: "inherit",
      cwd,
      env
    });
  });
  stack.command("status").description("Show builder stack container status").action(() => {
    try {
      execSync4(
        'docker ps -a --filter name=eve-builder-site --format "table {{.Names}}\\t{{.Status}}\\t{{.Ports}}"',
        { stdio: "inherit" }
      );
    } catch {
      console.log("No eve-builder-site container (run: eve builder stack up)");
    }
  });
}

